    let maxEdge = 0;
    for (const edge of edges) {
        if (edge[2] > maxEdge) maxEdge = edge[2];
    }

    class MinHeap {
        constructor() {
            this.heap = [];
        }

        push(val) {
            this.heap.push(val);
            this.bubbleUp(this.heap.length - 1);
        }

        pop() {
            if (this.heap.length === 0) return null;
            const min = this.heap[0];
            const last = this.heap.pop();
            if (this.heap.length > 0) {
                this.heap[0] = last;
                this.bubbleDown(0);
            }
            return min;
        }

        bubbleUp(idx) {
            while (idx > 0) {
                const parentIdx = Math.floor((idx - 1) / 2);
                if (this.heap[parentIdx][0] <= this.heap[idx][0]) break;
                [this.heap[parentIdx], this.heap[idx]] = [this.heap[idx], this.heap[parentIdx]];
                idx = parentIdx;
            }
        }

        bubbleDown(idx) {
            while (idx < this.heap.length) {
                const leftIdx = 2 * idx + 1;
                const rightIdx = 2 * idx + 2;
                let smallestIdx = idx;

                if (leftIdx < this.heap.length && this.heap[leftIdx][0] < this.heap[smallestIdx][0]) {
                    smallestIdx = leftIdx;
                }
                if (rightIdx < this.heap.length && this.heap[rightIdx][0] < this.heap[smallestIdx][0]) {
                    smallestIdx = rightIdx;
                }

                if (smallestIdx === idx) break;

                [this.heap[idx], this.heap[smallestIdx]] = [this.heap[smallestIdx], this.heap[idx]];
                idx = smallestIdx;
            }
        }

        isEmpty() {
            return this.heap.length === 0;
        }
    }

    const check = (x) => {
        const graph = Array.from({ length: n }, () => []);
        for (const [u, v, w] of edges) {
            if (w < x) continue;
            if (u !== 0 && u !== n-1 && !online[u]) continue;
            if (v !== 0 && v !== n-1 && !online[v]) continue;
            graph[u].push([v, w]);
        }

        const dist = new Array(n).fill(Number.MAX_SAFE_INTEGER);
        dist[0] = 0;
        const heap = new MinHeap();
        heap.push([0, 0]);

        while (!heap.isEmpty()) {
            const [cost, u] = heap.pop();
            if (cost !== dist[u]) continue;

            for (const [v, w] of graph[u]) {
                const newCost = cost + w;
                if (newCost > k) continue;
                if (v === n-1) {
                    return true;
                }
                if (newCost < dist[v]) {
                    dist[v] = newCost;
                    heap.push([newCost, v]);
                }
            }
        }
        return false;
    };

    let low = 0;
    let high = maxEdge;
    while (low <= high) {
        const mid = Math.floor((low + high) / 2);
        if (check(mid)) {
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }

    return high < 0 ? -1 : high;
}
